  ('optician-moex-01582', 'optician', 'optician-moex-109-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '等量屈光差的遠視患者與近視患者，如果他們的調節幅度量相等，則他們的調節近點（眼睛可以看清楚的 最近距離）的表現如何？', '["未矯正屈光差時，遠視者＝近視者", "未矯正屈光差時，近視者＞遠視者", "矯正屈光差後，遠視者＞近視者", "矯正屈光差後，遠視者＝近視者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:34+00:00", "source_pdf_sha1": "35cf199f6646", "answer_pdf_sha1": "a845aba7a8a1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
